mapper.sql:
SELECT A.SALE_PLCY_CD , A.SALE_PLCY_NM , A.SALE_STRT_DTTM , SUBSTR(A.SALE_STRT_DTTM, 1, 8) AS SALE_STRT_DT , SUBSTR(A.SALE_STRT_DTTM, 9, 6) AS SALE_STRT_TM , A.SALE_END_DTTM , SUBSTR(A.SALE_END_DTTM, 1, 8) AS SALE_END_DT , SUBSTR(A.SALE_END_DTTM, 9, 6) AS SALE_END_TM , A.ORGN_TYPE , A.PLCY_TYPE_CD , FN_GET_CODENM('CMN0050', A.PLCY_TYPE_CD) AS PLCY_TYPE , A.PLCY_SCTN_CD , FN_GET_CODENM('ORG0007', A.PLCY_SCTN_CD) AS PLCY_SCTN , A.PRDT_SCTN_CD , A.APPL_SCTN_CD , FN_GET_CODENM('CMN0052', A.APPL_SCTN_CD) AS APPL_SCTN , A.SPRT_TP , FN_GET_CODENM('CMN0058', A.SPRT_TP) AS SPRT_TP_NM , A.INST_RATE , A.NEW_YN , A.MNP_YN , A.HCN_YN , A.HDN_YN , A.CNFM_YN , FN_GET_USRNM(A.CNFM_ID) AS CNFM_NM , A.CNFM_DTTM , A.SELF_OPEN_YN FROM MSP_SALE_PLCY_MST A WHERE #{stdrDt} BETWEEN SUBSTR(A.SALE_STRT_DTTM, 1, 8) AND SUBSTR(A.SALE_END_DTTM, 1, 8)
AND ( UPPER(A.SALE_PLCY_CD) = UPPER( #{searchVal} ) OR UPPER(A.SALE_PLCY_NM) LIKE '%' || UPPER( #{searchVal} ) || '%' )
AND A.PLCY_TYPE_CD = #{searchPlcyTypeCd}
AND A.PLCY_SCTN_CD = #{searchPlcySctnCd}
AND A.SPRT_TP = #{searchSupportTypeCd}
ORDER BY A.REGST_DTTM DESC

mapper.select:
/* plcyMapper.getAgncyTrgtList */ SELECT '' AS CHK , A.ORGN_ID , A.ORGN_NM , B.CD_DSC AS TYPE_NM FROM ORG_ORGN_INFO_MST A , CMN_GRP_CD_MST B WHERE A.TYPE_CD = '20' AND A.ORGN_STAT_CD = '4' AND A.TYPE_DTL_CD3 = B.CD_VAL AND B.GRP_ID = 'ORG0043' AND B.USG_YN = 'Y'
AND A.TYPE_DTL_CD2 = #{orgnType}
ORDER BY A.ORGN_NM

/* plcyMapper.getRateTrgtList */ SELECT '' AS CHK , A.RATE_GRP_CD , A.RATE_CD , A.RATE_NM , A.PAY_CL_CD , A.RATE_TYPE , A.DATA_TYPE , A.BASE_AMT FROM MSP_RATE_MST A WHERE A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P'
AND A.PAY_CL_CD = #{payClCd}
AND A.DATA_TYPE IN ('LTE', '5G')
AND A.DATA_TYPE = #{dataType}
AND A.RATE_TYPE IN ('00', #{rateType})
ORDER BY A.RATE_NM

/* plcyMapper.getRateArpuTrgtList */ SELECT X.RATE_GRP_CD , X.RATE_CD , X.RATE_NM FROM ( SELECT A.RATE_GRP_CD , A.RATE_CD , A.RATE_NM , ROW_NUMBER () OVER (ORDER BY A.RATE_NM ) SORT FROM MSP_RATE_MST A WHERE A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P' AND '20' = #{searchCd}
AND A.DATA_TYPE IN ('LTE', '5G')
AND A.DATA_TYPE = #{searchDataType}
AND a.RATE_TYPE in ('00', #{searchPlcySctnCd})
AND A.RATE_NM LIKE '%' || UPPER( #{searchVal} ) || '%'
UNION ALL SELECT A.CD_VAL AS RATE_GRP_CD , '' AS RATE_CD , A.CD_DSC AS RATE_NM , TO_NUMBER(NVL(A.ETC1, 99)) AS SORT FROM CMN_GRP_CD_MST A WHERE A.GRP_ID = 'CMN0046' AND A.USG_YN = 'Y' AND '10' = #{searchCd}
AND A.CD_DSC LIKE '%' || UPPER( #{searchVal} ) || '%'
) X ORDER BY X.SORT

mapper.insert:
/* plcyMapper.insertSalePlcyMst */
MERGE INTO MSP_SALE_PLCY_MST
USING DUAL
	ON ( SALE_PLCY_CD = #{salePlcyCd, jdbcType=VARCHAR} )
WHEN MATCHED THEN
	UPDATE SET
		  SALE_PLCY_NM = #{salePlcyNm, jdbcType=VARCHAR}
		, SALE_STRT_DTTM = #{saleStrtDt, jdbcType=VARCHAR} || #{saleStrtTm, jdbcType=VARCHAR}
		, SALE_END_DTTM = #{saleEndDt, jdbcType=VARCHAR} || #{saleEndTm, jdbcType=VARCHAR}
		, ORGN_TYPE = #{orgnType, jdbcType=VARCHAR}
		, PLCY_TYPE_CD = #{plcyTypeCd, jdbcType=VARCHAR}
		, PLCY_SCTN_CD = #{plcySctnCd, jdbcType=VARCHAR}
		, PRDT_SCTN_CD = #{prdtSctnCd, jdbcType=VARCHAR}
		, APPL_SCTN_CD = #{applSctnCd, jdbcType=VARCHAR}
		, SPRT_TP = #{sprtTp, jdbcType=VARCHAR}
		, INST_RATE = #{instRate, jdbcType=VARCHAR}
		, NEW_YN = NVL( #{newYn, jdbcType=VARCHAR}, 'N' )
		, MNP_YN = NVL( #{mnpYn, jdbcType=VARCHAR}, 'N' )
		, HCN_YN = NVL( #{hcnYn, jdbcType=VARCHAR}, 'N' )
		, HDN_YN = NVL( #{hdnYn, jdbcType=VARCHAR}, 'N' )
		, SELF_OPEN_YN = NVL( #{selfOpenYn, jdbcType=VARCHAR}, 'N' )
		, RVISN_ID = #{userId, jdbcType=VARCHAR}
		, RVISN_DTTM = SYSDATE
WHEN NOT MATCHED THEN
	INSERT (
		  SALE_PLCY_CD
		, SALE_PLCY_NM
		, SALE_STRT_DTTM
		, SALE_END_DTTM
		, ORGN_TYPE
		, PLCY_TYPE_CD
		, PLCY_SCTN_CD
		, PRDT_SCTN_CD
		, APPL_SCTN_CD
		, SPRT_TP
		, INST_RATE
		, NEW_YN
		, MNP_YN
		, HCN_YN
		, HDN_YN
		, SELF_OPEN_YN
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
	)VALUES(
		  #{salePlcyCd, jdbcType=VARCHAR}
		, #{salePlcyNm, jdbcType=VARCHAR}
		, #{saleStrtDt, jdbcType=VARCHAR} || #{saleStrtTm, jdbcType=VARCHAR}
		, #{saleEndDt, jdbcType=VARCHAR} || #{saleEndTm, jdbcType=VARCHAR}
		, #{orgnType, jdbcType=VARCHAR}
		, #{plcyTypeCd, jdbcType=VARCHAR}
		, #{plcySctnCd, jdbcType=VARCHAR}
		, #{prdtSctnCd, jdbcType=VARCHAR}
		, #{applSctnCd, jdbcType=VARCHAR}
		, #{sprtTp, jdbcType=VARCHAR}
		, #{instRate, jdbcType=VARCHAR}
		, NVL( #{newYn, jdbcType=VARCHAR}, 'N' )
		, NVL( #{mnpYn, jdbcType=VARCHAR}, 'N' )
		, NVL( #{hcnYn, jdbcType=VARCHAR}, 'N' )
		, NVL( #{hdnYn, jdbcType=VARCHAR}, 'N' )
		, NVL( #{selfOpenYn, jdbcType=VARCHAR}, 'N' )
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
	)

