mapper.sql:
SELECT DISTINCT A.SALE_PLCY_CD , A.RATE_CD , A.PRDT_ID , A.OLD_YN , A.AGRM_TRM , A.OPER_TYPE , A.ORGN_ID , A.HNDST_AMT , NVL(B.SUBSD_AMT, 0) AS SUBSD_AMT , A.HNDST_AMT - NVL(B.SUBSD_AMT, 0) AS INST_AMT , ROUND( ( A.HNDST_AMT - NVL(B.SUBSD_AMT, 0) ) * A.INST_RATE / 100, -1 ) AS INST_CMSN , CASE WHEN A.SPRT_TP ='KD' --할인유형 : 단말할인 AND A.PLCY_TYPE_CD = 'D' --정책유형 : 직영 AND A.ORGN_TYPE = 'CS7' --채널유형 : 직영 AND A.ORGN_ID = '1100011741' --직영온라인 THEN CASE WHEN ROUND( NVL(B.SUBSD_AMT, 0) * A.RATE , -2 ) > A.HNDST_AMT - NVL(B.SUBSD_AMT, 0) THEN A.HNDST_AMT - NVL(B.SUBSD_AMT, 0) ELSE ROUND( NVL(B.SUBSD_AMT, 0) * A.RATE , -2 ) END ELSE 0 END AS AGNCY_SUBSD_AMT , A.HNDST_AMT - NVL(B.SUBSD_AMT, 0) AS AGNCY_SUBSD_MAX , A.SPRT_TP , A.SALE_STRT_DTTM , A.BASE_AMT FROM ( SELECT PLCY.SALE_PLCY_CD , PLCY.INST_RATE , SUBSTR(PLCY.SALE_STRT_DTTM, 1, 8) AS STRT_DT , SUBSTR(PLCY.SALE_END_DTTM, 1, 8) AS END_DT , RATE.RATE_CD , PRDT.PRDT_ID , PRDT.OLD_YN , NVL(AGRM.AGRM_TRM, '0') AGRM_TRM , OPER.OPER_TYPE , ORGN.ORGN_ID , ROUND( PRIC.OUT_UNIT_PRIC * 1.1 ) AS HNDST_AMT , GRP.ETC1 AS RATE , PLCY.SPRT_TP , PLCY.SALE_STRT_DTTM , RATEMST.BASE_AMT , PLCY.PLCY_TYPE_CD , PLCY.ORGN_TYPE FROM MSP_SALE_PLCY_MST PLCY , MSP_SALE_RATE_MST RATE , MSP_SALE_PRDT_MST PRDT , MSP_SALE_AGRM_MST AGRM , MSP_SALE_OPER_MST OPER , MSP_SALE_ORGN_MST ORGN , CMN_HNDST_AMT PRIC , CMN_GRP_CD_MST GRP , MSP_RATE_MST RATEMST WHERE PLCY.SALE_PLCY_CD = RATE.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = PRDT.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = AGRM.SALE_PLCY_CD(+) AND PLCY.SALE_PLCY_CD = OPER.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = ORGN.SALE_PLCY_CD AND PRDT.PRDT_ID = PRIC.RPRS_PRDT_ID AND PRDT.OLD_YN = PRIC.OLD_YN AND PLCY.SALE_STRT_DTTM BETWEEN PRIC.UNIT_PRIC_APPL_DTTM AND PRIC.UNIT_PRIC_EXPR_DTTM AND GRP.GRP_ID = 'CMN0051' AND GRP.CD_VAL = '10' AND RATE.RATE_CD = RATEMST.RATE_CD AND PLCY.SALE_PLCY_CD = #{salePlcyCd}
AND ORGN.ORGN_ID = #{orgnId}
AND RATE.RATE_CD = #{rateCd}
) A , MSP_OFCL_SUBSD_MST B WHERE A.RATE_CD = B.RATE_CD(+) AND A.PRDT_ID = B.PRDT_ID(+) AND A.OLD_YN = B.OLD_YN(+) AND DECODE(A.OPER_TYPE, 'HDN3', 'HCN3', A.OPER_TYPE) = B.OPER_TYPE(+) AND A.AGRM_TRM = B.AGRM_TRM(+) AND DECODE(#{addRateYn}, 'Y', TO_CHAR(SYSDATE, 'YYYYMMDD'), A.STRT_DT) >= B.APPL_STRT_DT(+) AND DECODE(#{addRateYn}, 'Y', TO_CHAR(SYSDATE, 'YYYYMMDD'), A.END_DT) <= B.APPL_END_DT(+)

SELECT DISTINCT PLCY.SALE_PLCY_CD , RATE.RATE_CD , PRDT.PRDT_ID , PRDT.OLD_YN , NVL(AGRM.AGRM_TRM, '0') AS AGRM_TRM , OPER.OPER_TYPE , ORGN.ORGN_ID , ROUND( PRIC.OUT_UNIT_PRIC * 1.1 ) AS HNDST_AMT , 0 AS SUBSD_AMT , ROUND( PRIC.OUT_UNIT_PRIC * 1.1 ) AS INST_AMT , ROUND( ROUND( PRIC.OUT_UNIT_PRIC * 1.1 ) * PLCY.INST_RATE / 100, -1 ) AS INST_CMSN , 0 AS AGNCY_SUBSD_MAX , 0 AS AGNCY_SUBSD_AMT , PLCY.SPRT_TP , PLCY.SALE_STRT_DTTM , RATEMST.BASE_AMT FROM MSP_SALE_PLCY_MST PLCY , MSP_SALE_RATE_MST RATE , MSP_SALE_PRDT_MST PRDT , MSP_SALE_AGRM_MST AGRM , MSP_SALE_OPER_MST OPER , MSP_SALE_ORGN_MST ORGN , CMN_HNDST_AMT PRIC , MSP_RATE_MST RATEMST WHERE PLCY.SALE_PLCY_CD = RATE.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = PRDT.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = AGRM.SALE_PLCY_CD(+) AND PLCY.SALE_PLCY_CD = OPER.SALE_PLCY_CD AND PLCY.SALE_PLCY_CD = ORGN.SALE_PLCY_CD AND PRDT.PRDT_ID = PRIC.RPRS_PRDT_ID AND PRDT.OLD_YN = PRIC.OLD_YN AND PLCY.SALE_STRT_DTTM BETWEEN PRIC.UNIT_PRIC_APPL_DTTM AND PRIC.UNIT_PRIC_EXPR_DTTM AND RATE.RATE_CD = RATEMST.RATE_CD AND PLCY.SALE_PLCY_CD = #{salePlcyCd}
AND ORGN.ORGN_ID = #{orgnId}
AND RATE.RATE_CD = #{rateCd}

mapper.insert:
/* plcyMapper.insertSaleSubsdMst */ INSERT INTO MSP_SALE_SUBSD_MST ( SALE_PLCY_CD , RATE_CD , PRDT_ID , OLD_YN , AGRM_TRM , OPER_TYPE , ORGN_ID , HNDST_AMT , SUBSD_AMT , INST_AMT , INST_CMSN , AGNCY_SUBSD_MAX , AGNCY_SUBSD_AMT , SPRT_TP , BASE_AMT , DC_AMT , ADD_DC_AMT , REGST_ID , REGST_DTTM , RVISN_ID , RVISN_DTTM ) SELECT PLCYINFO.SALE_PLCY_CD ,PLCYINFO.RATE_CD ,PLCYINFO.PRDT_ID ,PLCYINFO.OLD_YN ,PLCYINFO.AGRM_TRM ,PLCYINFO.OPER_TYPE ,PLCYINFO.ORGN_ID ,PLCYINFO.HNDST_AMT ,PLCYINFO.SUBSD_AMT ,PLCYINFO.INST_AMT ,PLCYINFO.INST_CMSN ,PLCYINFO.AGNCY_SUBSD_MAX ,PLCYINFO.AGNCY_SUBSD_AMT ,PLCYINFO.SPRT_TP ,NVL(PLCYINFO.BASE_AMT, 0) AS BASE_AMT ,NVL(RATESPECKD.DC_AMT, 0) AS DC_AMT ,DECODE(PLCYINFO.SPRT_TP, 'KD', 0, 'SM', NVL(RATESPECSM.DC_AMT, 0), NVL(RATESPECPM.DC_AMT, 0)) AS ADD_DC_AMT , #{userId} , SYSDATE , #{userId} , SYSDATE FROM (
) PLCYINFO , MSP_RATE_SPEC RATESPECKD , MSP_RATE_SPEC RATESPECPM , MSP_RATE_SPEC RATESPECSM WHERE PLCYINFO.RATE_CD = RATESPECKD.RATE_CD(+) AND PLCYINFO.AGRM_TRM = RATESPECKD.AGRM_TRM(+) AND RATESPECKD.SPRT_TP(+) = 'KD' AND PLCYINFO.RATE_CD = RATESPECPM.RATE_CD(+) AND PLCYINFO.AGRM_TRM = RATESPECPM.AGRM_TRM(+) AND RATESPECPM.SPRT_TP(+) = 'PM' AND PLCYINFO.RATE_CD = RATESPECSM.RATE_CD(+) AND PLCYINFO.AGRM_TRM = RATESPECSM.AGRM_TRM(+) AND RATESPECSM.SPRT_TP(+) = 'SM'
AND PLCYINFO.SALE_STRT_DTTM BETWEEN RATESPECKD.APPL_STRT_DTTM(+) AND RATESPECKD.APPL_END_DTTM(+) AND PLCYINFO.SALE_STRT_DTTM BETWEEN RATESPECPM.APPL_STRT_DTTM(+) AND RATESPECPM.APPL_END_DTTM(+) AND PLCYINFO.SALE_STRT_DTTM BETWEEN RATESPECSM.APPL_STRT_DTTM(+) AND RATESPECSM.APPL_END_DTTM(+)
AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN RATESPECKD.APPL_STRT_DTTM(+) AND RATESPECKD.APPL_END_DTTM(+) AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN RATESPECPM.APPL_STRT_DTTM(+) AND RATESPECPM.APPL_END_DTTM(+) AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN RATESPECSM.APPL_STRT_DTTM(+) AND RATESPECSM.APPL_END_DTTM(+)

mapper.select:
/* plcyMapper.getSaleRateList */
SELECT DECODE(A.RATE_CD, NULL, '0', '1') CHK , A.SALE_PLCY_CD , B.RATE_CD , B.RATE_NM , B.BASE_AMT FROM MSP_SALE_RATE_MST A , MSP_RATE_MST B , MSP_SALE_PLCY_MST C WHERE A.RATE_CD(+) = B.RATE_CD AND B.SERVICE_TYPE = 'P' AND B.PAY_CL_CD LIKE DECODE(C.ORGN_TYPE||C.PLCY_SCTN_CD, 'CS7'||'02', '%', 'PO') /* 직영의 USIM인 경우 선불요금제도 조회 */ AND B.APPL_END_DT = '99991231' AND C.SALE_PLCY_CD = #{salePlcyCd}
AND B.DATA_TYPE IN ('LTE', '5G')
AND B.DATA_TYPE = C.PRDT_SCTN_CD
AND (B.RATE_TYPE = '00' OR B.RATE_TYPE LIKE DECODE(C.ORGN_TYPE||C.PLCY_SCTN_CD, 'CS7'||'01', '%' , 'CS4'||'01' , '%' , C.PLCY_SCTN_CD) || '%') /* 직영의 단말기인 경우 제품구분없이 조회 */ AND A.SALE_PLCY_CD(+) = #{salePlcyCd} ORDER BY B.RATE_NM

mapper.update:
/* plcyMapper.setPlcyConfirm */
UPDATE  MSP_SALE_PLCY_MST
SET       CNFM_YN         = 'Y'
        , CNFM_ID       = #{userId}
        , CNFM_DTTM     = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
        , RVISN_ID      = #{userId}
        , RVISN_DTTM    = SYSDATE
WHERE   SALE_PLCY_CD    = #{salePlcyCd}

/* plcyMapper.setPlcyCancel */
UPDATE  MSP_SALE_PLCY_MST
SET       CNFM_YN         = 'N'
        , CNFM_ID       = ''
        , CNFM_DTTM     = ''
        , RVISN_ID      = #{userId}
        , RVISN_DTTM    = SYSDATE
WHERE   SALE_PLCY_CD    = #{salePlcyCd}

mapper.sql:
SELECT A.SALE_PLCY_CD , A.SALE_PLCY_NM , A.SALE_STRT_DTTM , TO_CHAR(TO_DATE(A.SALE_STRT_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STRT_DTM , A.SALE_END_DTTM , TO_CHAR(TO_DATE(A.SALE_END_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS END_DTM , B.RATE_CD , D.RATE_NM , B.ORGN_ID , C.ORGN_NM , B.PRDT_ID , E.PRDT_CODE , E.PRDT_NM , B.OLD_YN , DECODE(B.OLD_YN, 'N', '신품', '중고') AS OLD_NM , B.AGRM_TRM , B.OPER_TYPE , F.CD_DSC AS OPER_TYPE_NM , B.HNDST_AMT , B.SUBSD_AMT , B.AGNCY_SUBSD_MAX , B.AGNCY_SUBSD_AMT
, CASE WHEN B.INST_AMT < 0 THEN 0 ELSE B.INST_AMT END AS INST_AMT_ORGN , CASE WHEN B.INST_CMSN < 0 THEN 0 ELSE B.INST_CMSN END AS INST_CMSN_ORGN , CASE WHEN B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) < 0 THEN 0 ELSE B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) END AS INST_AMT , CASE WHEN NVL( A.INST_RATE, 0 ) = 0 THEN 0 ELSE CASE WHEN B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) < 0 THEN 0 WHEN A.INST_RATE = 0 THEN 0 ELSE ROUND( ( B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) ) * A.INST_RATE / 100, -1 ) END END AS INST_CMSN , '일반' AS SELF_OPEN_NM , 'https://www.ktmmobile.com/request/marketRequest.do?a=' || B.ORGN_ID || '&o=' || B.OPER_TYPE || '&s=' || B.SALE_PLCY_CD || '&p=' || E.PRDT_CODE || '&g=' || A.SPRT_TP || '&r=' || B.RATE_CD || '&y=' || B.AGRM_TRM || '&u=' AS URL_PATH , 'https://www.ktmmobile.com/m/request/marketRequest.do?a=' || B.ORGN_ID || '&o=' || B.OPER_TYPE || '&s=' || B.SALE_PLCY_CD || '&p=' || E.PRDT_CODE || '&g=' || A.SPRT_TP || '&r=' || B.RATE_CD || '&y=' || B.AGRM_TRM || '&u=' AS MURL_PATH , CASE WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '00' THEN 'https://www.ktmmobile.com/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '01' THEN 'https://www.ktmmobile.com/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID || '&r=' || B.RATE_CD ELSE '' END AS URL_PATH2 , CASE WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '00' THEN 'https://www.ktmmobile.com/m/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '01' THEN 'https://www.ktmmobile.com/m/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID || '&r=' || B.RATE_CD ELSE '' END AS MURL_PATH2
, G.NEW_CMSN_AMT , G.MNP_CMSN_AMT , G.HCN_CMSN_AMT , G.HDN_CMSN_AMT , B.SPRT_TP , FN_GET_CODENM('CMN0058', B.SPRT_TP) AS SPRT_TP_NM , B.BASE_AMT , B.DC_AMT , B.ADD_DC_AMT FROM MSP_SALE_PLCY_MST A , MSP_SALE_SUBSD_MST B , ORG_ORGN_INFO_MST C , MSP_RATE_MST D , CMN_INTM_MDL E , CMN_GRP_CD_MST F , MSP_SALE_PRDT_MST G WHERE A.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND B.ORGN_ID = C.ORGN_ID AND B.RATE_CD = D.RATE_CD AND D.APPL_END_DT = '99991231' AND D.SERVICE_TYPE = 'P' AND B.PRDT_ID = E.PRDT_ID AND B.OPER_TYPE = F.CD_VAL AND F.GRP_ID = 'CMN0049' AND B.SALE_PLCY_CD = G.SALE_PLCY_CD AND B.PRDT_ID = G.PRDT_ID AND B.OLD_YN = G.OLD_YN AND #{stdrDt} BETWEEN SUBSTR(A.SALE_STRT_DTTM, 1, 8) AND SUBSTR(A.SALE_END_DTTM, 1, 8)
AND B.ORGN_ID = #{orgnId}
AND ( A.SALE_PLCY_CD LIKE '%' || #{searchVal} || '%' OR A.SALE_PLCY_NM LIKE '%' || #{searchVal} || '%' )
AND B.AGRM_TRM = #{agrmTrm}
AND B.OPER_TYPE = #{operType}
AND B.RATE_CD = #{rateCd}
AND B.PRDT_ID = #{prdtId}
AND B.SPRT_TP = #{sprtTp}

SELECT A.SALE_PLCY_CD , A.SALE_PLCY_NM , A.SALE_STRT_DTTM , TO_CHAR(TO_DATE(A.SALE_STRT_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STRT_DTM , A.SALE_END_DTTM , TO_CHAR(TO_DATE(A.SALE_END_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS END_DTM , B.RATE_CD , D.RATE_NM , B.ORGN_ID , C.ORGN_NM , B.PRDT_ID , E.PRDT_CODE , E.PRDT_NM , B.OLD_YN , DECODE(B.OLD_YN, 'N', '신품', '중고') AS OLD_NM , B.AGRM_TRM , B.OPER_TYPE , F.CD_DSC AS OPER_TYPE_NM , B.HNDST_AMT , B.SUBSD_AMT , B.AGNCY_SUBSD_MAX , B.AGNCY_SUBSD_AMT
, CASE WHEN B.INST_AMT < 0 THEN 0 ELSE B.INST_AMT END AS INST_AMT_ORGN , CASE WHEN B.INST_CMSN < 0 THEN 0 ELSE B.INST_CMSN END AS INST_CMSN_ORGN , CASE WHEN B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) < 0 THEN 0 ELSE B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) END AS INST_AMT , CASE WHEN NVL( A.INST_RATE, 0 ) = 0 THEN 0 ELSE CASE WHEN B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) < 0 THEN 0 WHEN A.INST_RATE = 0 THEN 0 ELSE ROUND( ( B.HNDST_AMT - ( B.SUBSD_AMT + B.AGNCY_SUBSD_AMT ) ) * A.INST_RATE / 100, -1 ) END END AS INST_CMSN , '셀프개통' AS SELF_OPEN_NM , 'https://www.ktmmobile.com/appForm/appAgentFormDesignView.do?a=' || B.ORGN_ID || '&o=' || B.OPER_TYPE || '&s=' || B.SALE_PLCY_CD || '&p=' || E.PRDT_CODE || '&g=' || A.SPRT_TP || '&r=' || B.RATE_CD || '&y=' || B.AGRM_TRM || '&u=' AS URL_PATH , 'https://www.ktmmobile.com/m/appForm/appAgentFormDesignView.do?a=' || B.ORGN_ID || '&o=' || B.OPER_TYPE || '&s=' || B.SALE_PLCY_CD || '&p=' || E.PRDT_CODE || '&g=' || A.SPRT_TP || '&r=' || B.RATE_CD || '&y=' || B.AGRM_TRM || '&u=' AS MURL_PATH , CASE /*위탁온라인(셀프+상담사) URL생성 (00:조직코드만 생성, 01:기존과같이생성 - TOSS요청사항)*/ WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '00' THEN 'https://www.ktmmobile.com/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '01' THEN 'https://www.ktmmobile.com/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID || '&r=' || B.RATE_CD ELSE '' END AS URL_PATH2 , CASE WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '00' THEN 'https://www.ktmmobile.com/m/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID WHEN (SELECT EXPNSN_STR_VAL1 FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuAgentList' AND DTL_CD = #{orgnId}) = '01' THEN 'https://www.ktmmobile.com/m/appForm/appJehuFormDesignView.do?a=' || B.ORGN_ID || '&r=' || B.RATE_CD ELSE '' END AS MURL_PATH2
, G.NEW_CMSN_AMT , G.MNP_CMSN_AMT , G.HCN_CMSN_AMT , G.HDN_CMSN_AMT , B.SPRT_TP , FN_GET_CODENM('CMN0058', B.SPRT_TP) AS SPRT_TP_NM , B.BASE_AMT , B.DC_AMT , B.ADD_DC_AMT FROM MSP_SALE_PLCY_MST A , MSP_SALE_SUBSD_MST B , ORG_ORGN_INFO_MST C , MSP_RATE_MST D , CMN_INTM_MDL E , CMN_GRP_CD_MST F , MSP_SALE_PRDT_MST G WHERE A.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND B.ORGN_ID = C.ORGN_ID AND B.RATE_CD = D.RATE_CD AND D.APPL_END_DT = '99991231' AND D.SERVICE_TYPE = 'P' AND B.PRDT_ID = E.PRDT_ID AND B.OPER_TYPE = F.CD_VAL AND F.GRP_ID = 'CMN0049' AND B.SALE_PLCY_CD = G.SALE_PLCY_CD AND B.PRDT_ID = G.PRDT_ID AND B.OLD_YN = G.OLD_YN AND #{stdrDt} BETWEEN SUBSTR(A.SALE_STRT_DTTM, 1, 8) AND SUBSTR(A.SALE_END_DTTM, 1, 8) AND A.SELF_OPEN_YN = 'Y'
AND B.ORGN_ID = #{orgnId}
AND ( A.SALE_PLCY_CD LIKE '%' || #{searchVal} || '%' OR A.SALE_PLCY_NM LIKE '%' || #{searchVal} || '%' )
AND B.AGRM_TRM = #{agrmTrm}
AND B.OPER_TYPE = #{operType}
AND B.RATE_CD = #{rateCd}
AND B.PRDT_ID = #{prdtId}
AND B.SPRT_TP = #{sprtTp}

