/* plcyMapper.updateAgncySubsdAmt */
UPDATE  MSP_SALE_SUBSD_MST
SET     AGNCY_SUBSD_AMT = CASE WHEN AGNCY_SUBSD_MAX  >=  #{agncySubsdAmt, jdbcType=INTEGER} THEN #{agncySubsdAmt, jdbcType=INTEGER}
                               ELSE AGNCY_SUBSD_MAX
                          END 
        , RVISN_ID      = #{userId, jdbcType=VARCHAR}
        , RVISN_DTTM    = SYSDATE
WHERE   SALE_PLCY_CD    = #{salePlcyCd, jdbcType=VARCHAR}
AND     ORGN_ID         = #{orgnId, jdbcType=VARCHAR}
AND     PRDT_ID         = #{prdtId, jdbcType=VARCHAR}
AND     OLD_YN          = #{oldYn, jdbcType=VARCHAR}


AND     RATE_CD         = #{rateCd, jdbcType=VARCHAR}


AND     AGRM_TRM        = #{agrmTrm, jdbcType=VARCHAR}


AND     OPER_TYPE       = #{operType, jdbcType=VARCHAR}

