/* plcyMapper.getPlcyRateAddList */ SELECT #{salePlcyCd} AS SALE_PLCY_CD, #{sprtTp} AS SPRT_TP, A.RATE_GRP_CD, A.RATE_CD, A.RATE_NM, A.BASE_AMT FROM MSP_RATE_MST A WHERE A.SERVICE_TYPE = 'P' AND A.APPL_END_DT = '99991231' AND A.PAY_CL_CD LIKE DECODE(#{orgnType}||#{plcySctnCd}, 'CS7'||'02', '%', 'PO') /* 직영의 USIM인 경우 선불요금제도 조회 */
