AND A.DATA_TYPE = #{prdtSctnCd}
AND A.RATE_TYPE IN ('00', #{plcySctnCd}) /* 직영의 단말기인 경우 제품구분없이 조회 */
AND NOT EXISTS ( SELECT 1 FROM MSP_SALE_RATE_MST WHERE RATE_CD = A.RATE_CD AND SALE_PLCY_CD = #{salePlcyCd} ) ORDER BY RATE_GRP_CD, A.RATE_NM

SELECT MBLPHN_NUM AS mblphnNum
